    db = get_db()
    fields = ["name","personal_id","whatsapp","parent_name","parent_whatsapp","group_name","level","schedule_days","schedule_time","teacher","course","status","notes"]
    sets = ", ".join(f"{f}=?" for f in fields if f in d)
