def generate_local_answer(q, absent_names, overdue_pay, pending_task_list, high_absence, total_students, absent_today, pending_pay, pending_tasks, open_viol):
    q = q.lower()
    if "ØºØ§Ø¦Ø¨" in q or "Ø­Ø¶ÙØ±" in q or "ØºÙØ§Ø¨" in q:
        if absent_names:
            return f"Ø§ÙØºØ§Ø¦Ø¨ÙÙ Ø§ÙÙÙÙ ({absent_today} Ø·Ø§ÙØ¨):\n" + "\n".join(f"â¢ {n}" for n in absent_names)
        return "ÙØ§ ÙÙØ¬Ø¯ ØºÙØ§Ø¨ ÙØ³Ø¬Ù Ø§ÙÙÙÙ Ø­ØªÙ Ø§ÙØ¢Ù."
    if "Ø¯ÙØ¹" in q or "ÙØ³Ø·" in q or "ÙØ§Ù" in q:
        r = f"Ø§ÙØ¯ÙØ¹Ø§Øª Ø§ÙÙØ¹ÙÙØ©: {pending_pay} Ø¯ÙØ¹Ø©\nØ£Ø¨Ø±Ø²ÙØ§:\n"
        for p in overdue_pay:
            r += f"â¢ {p['student_name']} â {p['amount']} BD (ÙØ³ØªØ­Ù {p['due_date']})\n"
        return r
    if "ÙÙØ§Ù" in q or "ÙØªØ£Ø®Ø±" in q:
        r = f"Ø§ÙÙÙØ§Ù Ø§ÙÙØ¹ÙÙØ©: {pending_tasks}\n"
        for t in pending_task_list:
            r += f"â¢ {t['title']} ({t['department']}) â {t['due_date']}\n"
        return r
    if "ÙØ³Ø¨Ø©" in q or "ÙØ«ÙØ±" in q or "ØºÙØ§Ø¨ Ø¹Ø§ÙÙ" in q:
        if high_absence:
            r = "Ø§ÙØ·ÙØ§Ø¨ Ø°ÙÙ ÙØ³Ø¨Ø© ØºÙØ§Ø¨ Ø¹Ø§ÙÙØ©:\n"
            for s in high_absence:
                pct = round(s['absences']/s['total']*100)
                r += f"â¢ {s['student_name']} â {pct}% ({s['absences']}/{s['total']} Ø­ØµØµ)\n"
            return r
        return "ÙØ§ ÙÙØ¬Ø¯ Ø·ÙØ§Ø¨ Ø¨ÙØ³Ø¨Ø© ØºÙØ§Ø¨ Ø¹Ø§ÙÙØ© Ø­Ø§ÙÙØ§Ù."
    if "ÙØ®Ø§ÙÙ" in q:
        return f"Ø§ÙÙØ®Ø§ÙÙØ§Øª Ø§ÙÙÙØªÙØ­Ø©: {open_viol} ÙØ®Ø§ÙÙØ©."
    if "Ø·Ø§ÙØ¨" in q or "Ø¹Ø¯Ø¯" in q:
        return f"Ø¥Ø¬ÙØ§ÙÙ Ø§ÙØ·ÙØ§Ø¨ Ø§ÙÙØ´Ø·ÙÙ: {total_students} Ø·Ø§ÙØ¨."
    return f"ÙÙØ®Øµ Ø§ÙÙØ±ÙØ² Ø§ÙÙÙÙ:\nâ¢ Ø§ÙØ·ÙØ§Ø¨ Ø§ÙÙØ´Ø·ÙÙ: {total_students}\nâ¢ Ø§ÙØºØ§Ø¦Ø¨ÙÙ Ø§ÙÙÙÙ: {absent_today}\nâ¢ Ø§ÙØ¯ÙØ¹Ø§Øª Ø§ÙÙØ¹ÙÙØ©: {pending_pay}\nâ¢ Ø§ÙÙÙØ§Ù Ø§ÙÙØ¹ÙÙØ©: {pending_tasks}\nâ¢ Ø§ÙÙØ®Ø§ÙÙØ§Øª Ø§ÙÙÙØªÙØ­Ø©: {open_viol}"

